+fn parse_serialize_getter(cx: &Ctxt, meta: &ParseNestedMeta) -> syn::Result<Option<syn::ExprPath>> {
+    if meta.input.peek(Token![=]) {
+        return parse_lit_into_expr_path(cx, SERIALIZE_GETTER, meta);
+    }
+
+    let content;
+    syn::parenthesized!(content in meta.input);
+    let getter = content.parse::<syn::ExprPath>()?;
+    if !content.is_empty() {
+        return Err(content.error("expected a single getter path"));
+    }
+    Ok(Some(getter))
+}
